#include <bits/stdc++.h>
using namespace std;
const int N = 100005;
int n, Q, rt;
int vis[N];
int dfn[N], rnk[N], cnt;
int dep[N], f[N][18];
int Min[N];
vector <int> vec[N];
priority_queue <int, vector <int>, greater <int> > q;
bool cmp (int x, int y) {
	return Min[x] < Min[y];
}
void dfs1 (int u) {
	Min[u] = u;
	dep[u] = dep[f[u][0]] + 1;
	for (int i = 1; i <= 17; i++) {
		f[u][i] = f[f[u][i - 1]][i - 1];
	}
	for (int i = 0; i < vec[u].size (); i++) {
		int v = vec[u][i];
		dfs1 (v);
		Min[u] = min (Min[u], Min[v]);
	}
}
void dfs2 (int u) {
	for (int i = 0; i < vec[u].size (); i++) {
		int v = vec[u][i];
		dfs2 (v);
	}
	dfn[u] = ++cnt;
	rnk[cnt] = u;
}
int main () {
	cin >> n >> Q;
	for (int i = 1; i <= n; i++) {
		cin >> f[i][0];
		if (!f[i][0]) {
			rt = i;
		} else {
			vec[f[i][0]].push_back (i);
		}
	}
	dfs1 (rt);
	for (int i = 1; i <= n; i++) {
		sort (vec[i].begin (), vec[i].end (), cmp);
	}
	dfs2 (rt);
	for (int i = 1; i <= n; i++) {
		q.push (i);
	}
	while (Q--) {
		int op, x;
		cin >> op >> x;
		if (op == 1) {
			int ans = 0; 
			for (int i = 1; i <= x; i++) {
				ans = q.top ();
				q.pop ();
				vis[rnk[ans]] = 1;
			}
			cout << rnk[ans] << '\n';
		} else {
			int ans = 0, y = x;
			for(int i = 17; ~i; i--) {
				if (vis[f[y][i]]) {
					y = f[y][i];
				}
			}
			vis[y] = 0;
			q.push (dfn[y]);
			cout << dep[x] - dep[y] << '\n';
		}
	}
	return 0;
}
